import type { LinListToolbarActionDef } from '@linm-soft-org/linm-web-common-components';

type ToolbarBase = {
  testIdPrefix: string;
  onRefresh: () => void;
  onEditConfig?: () => void;
  canView: boolean;
  onView: () => void;
  canEdit: boolean;
  onEdit: () => void;
  canCreate: boolean;
  onCreate: () => void;
  canViewLedger: boolean;
  onViewLedger: () => void;
};

function configAction(p: ToolbarBase): LinListToolbarActionDef {
  return {
    id: 'editConfig',
    placement: 'overflow',
    action: 'editConfig',
    visible: Boolean(p.onEditConfig),
    onClick: p.onEditConfig,
    testId: `${p.testIdPrefix}-list-config-btn`,
  };
}

export function buildPnkListToolbar(p: ToolbarBase & {
  canConfirm: boolean;
  onConfirm: () => void;
  canPost: boolean;
  onPost: () => void;
}): LinListToolbarActionDef[] {
  const prefix = p.testIdPrefix;
  return [
    { id: 'refresh', placement: 'left', action: 'refresh', onClick: p.onRefresh, testId: `${prefix}-toolbar-refresh-btn` },
    {
      id: 'confirm',
      placement: 'left',
      action: 'approve',
      label: 'Xác nhận',
      visible: p.canConfirm,
      onClick: p.onConfirm,
      testId: `${prefix}-toolbar-confirm-btn`,
    },
    {
      id: 'post',
      placement: 'left',
      action: 'approve',
      label: 'Ghi sổ',
      visible: p.canPost,
      onClick: p.onPost,
      testId: `${prefix}-toolbar-post-btn`,
    },
    {
      id: 'viewLedger',
      placement: 'overflow',
      action: 'viewLedger',
      label: 'Xem sổ kho',
      disabled: !p.canViewLedger,
      onClick: p.onViewLedger,
      testId: `${prefix}-toolbar-view-ledger-btn`,
    },
    configAction(p),
    { id: 'view', placement: 'right', action: 'view', disabled: !p.canView, onClick: p.onView, testId: `${prefix}-toolbar-view-btn` },
    { id: 'edit', placement: 'right', action: 'edit', disabled: !p.canEdit, onClick: p.onEdit, testId: `${prefix}-toolbar-edit-btn` },
    {
      id: 'create',
      placement: 'right',
      action: 'create',
      variant: 'primary',
      visible: p.canCreate,
      onClick: p.onCreate,
      testId: `${prefix}-toolbar-create-btn`,
    },
  ];
}

