import React, { useCallback, useEffect, useRef, useState } from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';
import type { DocumentPostingStatus, WmsPostedInventoryResult } from '../../services/kho/models';
import { formatDate } from '../../utils/formatters';
import { pollDocumentPostingStatus } from '../../utils/pollDocumentPostingStatus';
import styles from './WmsPostedInventoryModal.module.css';
import modalStyles from '../../styles/documentForm.module.css';

const IN_PROGRESS = new Set<DocumentPostingStatus>(['Queued', 'Processing']);

export interface WmsPostedInventoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  voucherTitle?: string;
  testIdPrefix: string;
  fetchPostedInventory: () => Promise<WmsPostedInventoryResult>;
  fetchPostingStatus?: () => Promise<{ postingStatus: DocumentPostingStatus; lastError?: string | null }>;
}

function statusLabel(status: string): string {
  switch (status) {
    case 'Queued': return 'Đang chờ ghi sổ';
    case 'Processing': return 'Đang ghi sổ';
    case 'Posted': return 'Đã ghi sổ';
    case 'Failed': return 'Ghi sổ thất bại';
    default: return 'Chưa ghi sổ';
  }
}

export const WmsPostedInventoryModal: React.FC<WmsPostedInventoryModalProps> = ({
  isOpen,
  onClose,
  voucherTitle,
  testIdPrefix,
  fetchPostedInventory,
  fetchPostingStatus,
}) => {
  const [loading, setLoading] = useState(false);
  const [polling, setPolling] = useState(false);
  const [data, setData] = useState<WmsPostedInventoryResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const cancelledRef = useRef(false);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      let ledger = await fetchPostedInventory();
      const status = ledger.postingStatus as DocumentPostingStatus;
      if (IN_PROGRESS.has(status) && fetchPostingStatus) {
        setPolling(true);
        await pollDocumentPostingStatus(fetchPostingStatus, { intervalMs: 1000, maxAttempts: 90 });
        if (cancelledRef.current) return;
        ledger = await fetchPostedInventory();
      }
      if (!cancelledRef.current) setData(ledger);
    } catch (e: unknown) {
      if (!cancelledRef.current) {
        setError(e instanceof Error && e.message === 'POSTING_POLL_TIMEOUT'
          ? 'Ghi sổ đang xử lý quá lâu. Vui lòng thử lại sau.'
          : 'Không thể tải dữ liệu sổ kho.');
      }
    } finally {
      if (!cancelledRef.current) {
        setLoading(false);
        setPolling(false);
      }
    }
  }, [fetchPostedInventory, fetchPostingStatus]);

  useEffect(() => {
    if (!isOpen) {
      cancelledRef.current = true;
      setData(null);
      setError(null);
      setPolling(false);
      return;
    }
    cancelledRef.current = false;
    void load();
    return () => { cancelledRef.current = true; };
  }, [isOpen, load]);

  const tid = (suffix: string) => `${testIdPrefix}-posted-inventory-${suffix}`;
  const status = String(data?.postingStatus ?? 'None');
  const showTable = status === 'Posted' && (data?.lines.length ?? 0) > 0;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Xem sổ kho" size="lg" data-testid={tid('modal')}>
      {voucherTitle && (
        <p style={{ marginBottom: 12, fontSize: 14, color: 'var(--color-text-secondary, #6c757d)' }} data-testid={tid('title')}>
          {voucherTitle}
        </p>
      )}

      {loading && !data && (
        <div className={styles.statusProcessing} data-testid={tid('loading')}>
          <i className="fas fa-spinner fa-spin" /> Đang tải sổ kho…
        </div>
      )}

      {error && <div className={styles.statusFailed} data-testid={tid('error')}>{error}</div>}

      {data && (
        <>
          <div className={styles.meta} data-testid={tid('meta')}>
            <span><strong>Trạng thái:</strong> {statusLabel(status)}</span>
            {data.postedAt && <span><strong>Ghi sổ lúc:</strong> {formatDate(data.postedAt)}</span>}
          </div>

          {IN_PROGRESS.has(status as DocumentPostingStatus) && (
            <div className={styles.statusProcessing} data-testid={tid('in-progress')}>
              <i className={`fas ${polling || loading ? 'fa-spinner fa-spin' : 'fa-clock'}`} />
              {data.message ?? (status === 'Processing' ? 'Đang ghi sổ…' : 'Đang chờ ghi sổ…')}
            </div>
          )}

          {status === 'Failed' && (
            <div className={styles.statusFailed} data-testid={tid('failed')}>
              {data.lastError ?? data.message ?? 'Ghi sổ thất bại.'}
            </div>
          )}

          {!showTable && data.message && status !== 'Failed' && !IN_PROGRESS.has(status as DocumentPostingStatus) && (
            <div className={styles.statusMessage} data-testid={tid('message')}>{data.message}</div>
          )}

          {showTable && (
            <div className={styles.tableWrap} data-testid={tid('table-wrap')}>
              <table className={styles.table} data-testid={tid('table')}>
                <thead>
                  <tr>
                    <th>Mã VT</th>
                    <th>Kho</th>
                    <th className={styles.kindCol}>Loại</th>
                    <th className={styles.qtyCol}>SL</th>
                    <th>Ngày</th>
                  </tr>
                </thead>
                <tbody>
                  {data.lines.map((line, i) => (
                    <tr key={`${line.materialCode}-${i}`} data-testid={tid(`line-${i}`)}>
                      <td><code>{line.materialCode}</code></td>
                      <td>{line.warehouseCode ?? '—'}</td>
                      <td className={styles.kindCol}>{line.movementKind}</td>
                      <td className={styles.qtyCol}>{line.quantity}</td>
                      <td>{formatDate(line.entryDate)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      <div className={modalStyles.modalActions}>
        <Button variant="secondary" onClick={onClose} data-testid={tid('close')}>Đóng</Button>
        {data && IN_PROGRESS.has(status as DocumentPostingStatus) && (
          <Button variant="primary" onClick={() => void load()} loading={loading} data-testid={tid('refresh')}>
            Làm mới
          </Button>
        )}
      </div>
    </Modal>
  );
};
