import type { MouseEvent } from 'react';

export function openWmsListRowMenu<T extends { id: string }>(
  e: MouseEvent,
  row: T,
  setActiveId: (id: string | null) => void,
  setRowMenu: (value: { x: number; y: number; row: T } | null) => void,
): void {
  e.preventDefault();
  e.stopPropagation();
  setActiveId(row.id);
  setRowMenu({ x: e.clientX, y: e.clientY, row });
}

export function canViewWmsInventoryLedger(status: string | undefined): boolean {
  return status === 'Posted';
}
